import Foundation

let scores = [85, 92, 78, 95, 88, 76]

// Searching
print("Contains 95: \(scores.contains(95))")
print("All passing (>70): \(scores.allSatisfy { $0 > 70 })")
print("Highest score: \(scores.max() ?? 0)")

// Sorting
let sortedDesc = scores.sorted(by: >)
print("Descending: \(sortedDesc)")

// Transforming
let doubled = scores.map { $0 * 2 }
print("Doubled: \(doubled)")

let above85 = scores.filter { $0 > 85 }
print("Above 85: \(above85)")

let total = scores.reduce(0, +)
let average = Double(total) / Double(scores.count)
print("Total: \(total), Average: \(String(format: "%.1f", average))")
